{
  "mode": "method",
  "tests": [
    {
      "name": "valid_user_login",
      "input": {
        "username": "testuser",
        "password": "correctpassword"
      },
      "output": {
        "status": "success",
        "message": "Login successful"
      },
      "notes": "Tests a valid login scenario."
    },
    {
      "name": "invalid_user_login",
      "input": {
        "username": "testuser",
        "password": "wrongpassword"
      },
      "output": {
        "status": "error",
        "message": "Invalid credentials"
      },
      "notes": "Tests an invalid login scenario."
    },
    {
      "name": "delete_user_without_ssoId",
      "input": {
        "userId": "12345"
      },
      "output": {
        "status": "success",
        "message": "User deleted"
      },
      "notes": "Tests DELETE operation without passing ssoUserId."
    },
    {
      "name": "check_permission_with_allowed_scope",
      "input": {
        "userId": "12345",
        "action": "view",
        "allowedScope": "machine"
      },
      "output": {
        "status": "success",
        "message": "Permission granted"
      },
      "notes": "Tests permission checking logic with allowedScope."
    },
    {
      "name": "check_permission_without_allowed_scope",
      "input": {
        "userId": "12345",
        "action": "edit",
        "allowedScope": "none"
      },
      "output": {
        "status": "error",
        "message": "Permission denied"
      },
      "notes": "Tests permission denial when no allowedScope is provided."
    },
    {
      "name": "delete_nonexistent_user",
      "input": {
        "userId": "99999"
      },
      "output": {
        "status": "error",
        "message": "User not found"
      },
      "notes": "Tests DELETE operation for a nonexistent user."
    },
    {
      "name": "login_with_empty_credentials",
      "input": {
        "username": "",
        "password": ""
      },
      "output": {
        "status": "error",
        "message": "Credentials cannot be empty"
      },
      "notes": "Tests login with empty username and password."
    },
    {
      "name": "check_permission_for_admin",
      "input": {
        "userId": "admin",
        "action": "delete",
        "allowedScope": "admin"
      },
      "output": {
        "status": "success",
        "message": "Permission granted"
      },
      "notes": "Tests permission for an admin user."
    }
  ],
  "assumptions": "User IDs are unique and valid. The system is connected to the database.",
  "notes": "Ensure that the UserController adheres to the permission-checking logic as per the v3 Java code."
}
